<style scoped>
.logo-svg {
  width: 100%;
  height: 100%;
}

.logo-path {
  fill: none;
  stroke: var(--fg-deeper);
  stroke-width: 2;
  stroke-linecap: round;
  stroke-linejoin: round;
  stroke-dasharray: 4800;
  stroke-dashoffset: 4800;
  animation: logo-draw 16s ease forwards infinite;
}

.logo-dot {
  fill: var(--fg-deeper);
  opacity: 0;
  animation: dot-appear 16s ease forwards infinite;
}

@keyframes logo-draw {
  0% {
    stroke-dashoffset: 4800;
    opacity: 0;
  }
  5% {
    opacity: 1;
  }
  50% {
    stroke-dashoffset: 0;
  }
  90% {
    stroke-dashoffset: 0;
    opacity: 1;
  }
  100% {
    stroke-dashoffset: -4800;
    opacity: 0;
  }
}

@keyframes dot-appear {
  0%, 45% {
    opacity: 0;
  }
  50% {
    opacity: 1;
  }
  90% {
    opacity: 1;
  }
  100% {
    opacity: 0;
  }
}

@media (prefers-reduced-motion: no-preference) {
  .logo-path,
  .logo-dot {
    animation: logo-draw 16s ease forwards infinite;
  }
}

@media (prefers-reduced-motion: reduce) {
  .logo-path {
    stroke-dasharray: none;
    animation: none;
    opacity: 1;
  }
  .logo-dot {
    animation: none;
    opacity: 1;
  }
}
</style>
